func Xfsetflags(cgtls *iqlibc.ppTLS, aaname ppuintptr, aaflags ppuint64) (cgr ppint32) {

	var aabsd_flags ppuint64
	pp_ = aabsd_flags
	aabsd_flags = ppuint64(0)

	if aaflags&ppuint64(mvEXT2_IMMUTABLE_FL) != 0 {
		aabsd_flags = aabsd_flags | ppuint64(mvUF_IMMUTABLE)
	}
	if aaflags&ppuint64(mvEXT2_APPEND_FL) != 0 {
		aabsd_flags = aabsd_flags | ppuint64(mvUF_APPEND)
	}
	if aaflags&ppuint64(mvEXT2_NODUMP_FL) != 0 {
		aabsd_flags = aabsd_flags | ppuint64(mvUF_NODUMP)
	}

	return Xchflags(cgtls, aaname, ppuint32(aabsd_flags))
}

